class Solution {
public:
    vector<int> maxScoreIndices(vector<int>& nums) {
        int n = nums.size();
        int totalOnes = accumulate(nums.begin(), nums.end(), 0);
        int maxScore = totalOnes;
        int currentScore = totalOnes;
        vector<int> result;
        result.push_back(0);

        for (int i = 0; i < n; ++i) {
            if (nums[i] == 0) {
                currentScore += 1;
            } else {
                currentScore -= 1;
            }
            if (currentScore > maxScore) {
                maxScore = currentScore;
                result.clear();
                result.push_back(i + 1);
            } else if (currentScore == maxScore) {
                result.push_back(i + 1);
            }
        }

        return result;
    }
};
